, call_detail as (
  select
    c.action_id
    ,c.call_start_time
    ,substr(cast(c.call_start_time as string), 1, 19) as call_start_time_str
    ,c.call_time_length
    ,c.user_id
    ,c.worker_id
    ,c.agent_name
    ,c.clue_stage
    ,u.grade
    ,if(u.phone is null, u.phone, if(u.phone rlike '^\\d+$', u.phone, cast(unbase64(u.phone) as string))) as phone
    ,d2.regiment_name
    ,d4.team_name
  from calls c
  left join dw.dim_user u on c.user_id = u.u_user
  left join dw.dim_crm_organization d2 on c.regiment_id = d2.id
  left join dw.dim_crm_organization d4 on c.team_id = d4.id
)

select
  cd.action_id
  ,cd.user_id
  ,cd.call_start_time_str
  ,cd.call_time_length
  ,cd.grade
  ,cd.clue_stage
  ,cd.phone
  ,cd.agent_name
  ,cd.regiment_name
  ,cd.team_name

  ,nullif(concat_ws('|', collect_list(o.good_name)), '') as good_name
  ,sum(o.amount) as amount
  ,nullif(concat_ws('|', collect_list(substr(cast(o.pay_time as string), 1, 19))), '') as pay_time

from call_detail cd
left join aws.crm_order_info o
  on cd.user_id = o.user_id
  and cast(cd.worker_id as int) = o.worker_id
  and o.good_kind_name_level_2 = '组合商品'
  and o.status = '支付成功'
  and o.pay_time >= cd.call_start_time
  and to_date(o.pay_time) >= '2026-03-02'
  and to_date(o.pay_time) <= '2026-03-08'
group by
  cd.action_id
  ,cd.user_id
  ,cd.call_start_time_str
  ,cd.call_start_time
  ,cd.call_time_length
  ,cd.grade
  ,cd.clue_stage
  ,cd.phone
  ,cd.agent_name
  ,cd.regiment_name
  ,cd.team_name
limit 100000
